-- 014_skill_reqlevel_fix.sql
-- Correct the per-level character-level requirement (reqLevel) for every skill.
--
-- The original spidpex import (006) stored a single flat tier value (1/20/40/60)
-- on every level of a skill, so the simulator let players max a skill the moment
-- they hit the tier floor. The authoritative per-level ladder comes from the
-- Chapter-5 client DB (TB_DefSkill_Player.LevelLimit) -- e.g. Dragon Scale unlocks
-- at char lv 60/62/64/66/68, not a flat 60. This migration replaces skills.levels
-- with the corrected ladder (sp/mp/cooldown/power are unchanged). Idempotent.

update skills as s
set req_level = v.req_level,
    levels = v.levels
